import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): version}
def build_lookup(data):
    lookup = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                lookup[(pname, tfm, pkg['id'])] = pkg['resolvedVersion']
    return lookup

bl = build_lookup(baseline)
al = build_lookup(after)

all_keys = sorted(set(bl.keys()) | set(al.keys()))

changes = []
unchanged = []
for key in all_keys:
    pname, tfm, pid = key
    bv = bl.get(key)
    av = al.get(key)
    if bv and av and bv == av:
        unchanged.append((pname, tfm, pid, av))
    elif bv and av and bv != av:
        changes.append((pname, tfm, pid, bv, av, 'Aligned to highest version'))
    elif bv and not av:
        changes.append((pname, tfm, pid, bv, '-', 'Removed'))
    elif not bv and av:
        changes.append((pname, tfm, pid, '-', av, 'Added'))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]} [{c[5]}]')
else:
    print('  None')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}): {u[2]} = {u[3]}')
"

